"""
Pose class for defining character poses.

A Pose is a snapshot of joint angles that defines a specific
position of the character (standing, walking, attacking, etc.)
"""

from typing import Dict, List, Optional, Any
from dataclasses import dataclass, field


@dataclass
class Pose:
    """
    A pose defines the angles for all joints at a specific moment.
    """
    name: str
    angles: Dict[str, float] = field(default_factory=dict)
    root_offset: tuple = (0, 0)  # Offset from default root position
    duration: float = 1.0  # Duration in seconds (for animation)

    def __post_init__(self):
        """Ensure angles is a dict."""
        if self.angles is None:
            self.angles = {}

    def set_angle(self, joint_name: str, angle: float):
        """Set angle for a specific joint."""
        self.angles[joint_name] = angle

    def get_angle(self, joint_name: str, default: float = 0) -> float:
        """Get angle for a specific joint."""
        return self.angles.get(joint_name, default)

    def copy(self, new_name: str = None) -> 'Pose':
        """Create a copy of this pose."""
        return Pose(
            name=new_name or f"{self.name}_copy",
            angles=self.angles.copy(),
            root_offset=self.root_offset,
            duration=self.duration
        )

    def blend(self, other: 'Pose', factor: float) -> 'Pose':
        """
        Blend this pose with another pose.

        Args:
            other: Pose to blend with
            factor: 0.0 = this pose, 1.0 = other pose

        Returns:
            New blended pose
        """
        result = Pose(name=f"{self.name}_blend")

        # Get all joint names from both poses
        all_joints = set(self.angles.keys()) | set(other.angles.keys())

        for joint in all_joints:
            angle1 = self.angles.get(joint, 0)
            angle2 = other.angles.get(joint, 0)
            # Handle angle wrapping for shortest path
            diff = angle2 - angle1
            while diff > 180:
                diff -= 360
            while diff < -180:
                diff += 360
            result.angles[joint] = angle1 + diff * factor

        # Blend root offset
        result.root_offset = (
            self.root_offset[0] + (other.root_offset[0] - self.root_offset[0]) * factor,
            self.root_offset[1] + (other.root_offset[1] - self.root_offset[1]) * factor
        )

        return result

    def __repr__(self):
        return f"Pose({self.name}, {len(self.angles)} joints)"


class PoseLibrary:
    """
    A collection of named poses that can be applied to rigs.
    """

    def __init__(self):
        self.poses: Dict[str, Pose] = {}

    def add(self, pose: Pose):
        """Add a pose to the library."""
        self.poses[pose.name] = pose

    def get(self, name: str) -> Optional[Pose]:
        """Get a pose by name."""
        return self.poses.get(name)

    def remove(self, name: str):
        """Remove a pose from the library."""
        if name in self.poses:
            del self.poses[name]

    def list_poses(self) -> List[str]:
        """List all pose names."""
        return list(self.poses.keys())

    def create_sequence(self, pose_names: List[str], transitions: int = 3) -> List[Pose]:
        """
        Create a sequence of poses with transitions.

        Args:
            pose_names: List of pose names to sequence
            transitions: Number of transition frames between poses

        Returns:
            List of poses including transitions
        """
        sequence = []

        for i, name in enumerate(pose_names):
            pose = self.get(name)
            if pose is None:
                continue

            if i == 0:
                sequence.append(pose)
            else:
                # Add transition frames
                prev_pose = sequence[-1] if sequence else pose
                for t in range(1, transitions + 1):
                    factor = t / (transitions + 1)
                    blended = prev_pose.blend(pose, factor)
                    blended.name = f"{prev_pose.name}_to_{pose.name}_{t}"
                    sequence.append(blended)
                sequence.append(pose)

        return sequence

